<template>
  <div class="wrapper">
    
    <div class="settings">

      <div class="settings-currency">
        <div class="settings-currency-select-wrapper">
          <select @change="changeCurrenc" class="settings-currency-select">
            <option value="BTCUSDT" :selected="getCurrentCurrency === 'BTCUSDT'" class="settings-currency-option">BTCUSDT</option>
            <option value="BNBBTC" :selected="getCurrentCurrency === 'BNBBTC'" class="settings-currency-option">BNBBTC</option>
            <option value="ETHBTC" :selected="getCurrentCurrency === 'ETHBTC'" class="settings-currency-option">ETHBTC</option>
          </select>
        </div>
      </div>

      <div class="settings-history">
        <ul class="settings-history-list">
          <li class="settings-history-list__item"
            v-for="(diff, i) in getUpdateData"
            :key="i"
            :class="[diff.currency === 'Смена валюты' ? 'settings-history-list__item--change' : '']">
            <div v-if="diff.currency === 'Смена валюты'">
              <p>{{diff.currency}}</p>
            </div>

            <div v-else>
              <p>Валюта: {{diff.currency}}</p>
              <p>Изменено ордеров типа "bid": {{diff.bids}}</p>
              <p>Изменено ордеров типа "ask": {{diff.asks}}</p>
              <p>Текущий ID: {{diff.currentId}}</p>
            </div>
          </li>
        </ul>
      </div>

    </div>

  </div>

</template>

<script>
import {mapActions, mapGetters} from "vuex";

export default {
  name: "settings",
  computed: {
    ...mapGetters([
      "getCurrentCurrency",
      "getUpdateData"
    ])
  },
  methods: {
  ...mapActions([
    "changeCurrency",
    "getOrderBook",
    "getOrderBookUpdate"
    ]),

    changeCurrenc(event) {
      this.changeCurrency(event);
      this.getOrderBook();
      this.getOrderBookUpdate();
    }
  },
}
</script>

<style lang="scss">
.settings {
  display: flex;
  flex-flow: row nowrap;
  align-items: flex-start;
  justify-content: flex-start;
}

.settings-currency { flex: 1 1 20%; }

.settings-currency-select-wrapper {
  display: inline-block;
  position: relative;

  &::after {
    content: "";
    display: block;
    width: 0;
    height: 0;
    border-left: 7px solid transparent;
    border-right: 7px solid transparent;
    border-top: 7px solid #333333;
    position: absolute;
    top: 14px;
    right: 15px;
    pointer-events: none;
  }
}

.settings-currency-select {
  width: 130px;
  padding: 10px;
  font-size: 16px;
  border: none;
  background-color: #efefef;
  appearance: none;
}

.settings-currency-option {
  padding: 4px 0;
  border: none;
}

.settings-history { flex: 1 1 80%; }

.settings-history-list {
  list-style-type: none;

  &__item {
    padding: 20px;
    margin-bottom: 15px;
    background-color: #efefef;

    &--change {
      color: #FFFFFF;
      background-color: #333333;
    }

    &:last-child { margin-bottom: 0; }
  }
}

@media(max-width: 820px) {
  .settings-currency { flex: 1 1 25%; }
  .settings-history { flex: 1 1 75%; }
}

@media(max-width: 680px) {
  .settings {
    flex-direction: column;
    align-items: center;
    justify-content: flex-start;
  }

  .settings-currency {
    flex: 1 1 100%;
    margin-bottom: 30px;
  }
  .settings-history {
    width: 100%;
    flex: 1 1 100%;
  }
}

@media(max-width: 480px) {
  .settings-history-list {
    &__item { padding: 15px; }
  }
}
</style>